const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);

function computeItemPremiums(items: any[]): number {
  const componentCounts: Record<string, number> = {};
  let premium = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      premium += BASE_PREMIUM[item.type] ?? 0;
    }
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    const unitPrice = BASE_PREMIUM[type] ?? 0;
    premium += count === BLOCK_SIZE ? BLOCK_PREMIUM : count * unitPrice;
  }

  return premium;
}

export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => {
    return { premium: computeItemPremiums(step.items) + PROCESSING_FEE };
  });
  return { results };
}

