import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns 5G processing fee for an empty item list", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result).toEqual({ results: [{ premium: 5 }] });
    });
    it("returns base premium plus fee for a single sword (100 + 5 = 105)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 105 }] });
    });
    it("returns base premium plus fee for a single amulet (60 + 5 = 65)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 65 }] });
    });
    it("returns base premium plus fee for a single staff (80 + 5 = 85)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 85 }] });
    });
    it("returns base premium plus fee for a single potion (40 + 5 = 45)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 45 }] });
    });
    it("sums base premiums for multiple items (sword + amulet = 160 + 5 = 165)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 165 }] });
    });
  });

  describe("Quote - component premiums", () => {
    it("returns 25G per component (2 runes = 50 + 5 = 55)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "rune" },
            { type: "rune" },
          ],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 55 }] });
    });
    it("applies building block discount for exactly 3 alike components (3 runes = 60 + 5 = 65)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 65 }] });
    });
    it("does not apply block discount for 4 alike components (4 runes = 100 + 5 = 105)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 105 }] });
    });
    it("does not apply block for 3 components of different types (2 runes + 1 moonstone = 75 + 5 = 80)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
          ],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 80 }] });
    });
    it("applies separate blocks for 3 runes and 3 moonstones (120 + 5 = 125)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 125 }] });
    });
    it("charges 175G base for 7 runes (no block, 7 * 25 = 175 + 5 = 180)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        }],
      });
      expect(result).toEqual({ results: [{ premium: 180 }] });
    });
  });

  describe("Quote - item-specific modifiers", () => {
    it("adds 50% cursed surcharge to cursed item base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 155 }] });
    });
    it("adds 30% high-enchantment surcharge for enchantment >= 5", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 135 }] });
    });
    it("applies both cursed and high-enchantment surcharges to the same item", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 185 }] });
    });
    it("does not apply high-enchantment surcharge for enchantment 4", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 105 }] });
    });
    it("applies cursed surcharge only to the cursed item in a multi-item policy", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: true },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 215 }] });
    });
  });

  describe("Quote - policy-wide modifiers", () => {
    it("applies 10% first-insurance surcharge on policy base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up discount on second quote step");
    it.todo("does not apply loyalty discount for customer with < 2 years");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword: 165G (100 base + 50 curse + 10 first + 5 fee)");
    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
    it.todo("rounds premium up in MHPCO's favor");
  });

  describe("Quote - errors", () => {
    it.todo("rejects unknown item type with non-zero exit");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("reimburses damage minus 100G deductible for a regular item");
    it.todo("applies deductible per damaged item (sword 500 + amulet 300 = 600 payout)");
    it.todo("reimburses component damage minus deductible (rune damage 200 = 100 payout)");
  });

  describe("Claim - enchantment and material clauses", () => {
    it.todo("reimburses at 50% for enchantment >= 8 then applies deductible");
    it.todo("fully reimburses dragon material then applies deductible");
    it.todo("applies 50% when both dragon material and enchantment >= 8 (50% wins)");
    it.todo("dragon material with enchantment < 8: full reimbursement minus deductible");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at 2x insurance sum");
    it.todo("tracks remaining cap across successive claims");
    it.todo("cap exhaustion: second claim reduced to remaining cap");
  });

  describe("Claim - errors", () => {
    it.todo("rejects claim for item not in policy");
    it.todo("rejects claim with more damages of a type than policy covers");
    it.todo("rejects claim with negative damage amount");
  });

  describe("CLI integration", () => {
    it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
  });
});

