const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

function computePremiumBreakdown(items: any[]): { itemPremiums: number; policyBase: number } {
  const componentCounts: Record<string, number> = {};
  let itemPremiums = 0;
  let policyBase = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      const basePremium = BASE_PREMIUM[item.type] ?? 0;
      policyBase += basePremium;
      const cursedSurcharge = item.cursed ? basePremium * 0.5 : 0;
      const enchantmentSurcharge = item.enchantment >= 5 ? basePremium * 0.3 : 0;
      itemPremiums += basePremium + cursedSurcharge + enchantmentSurcharge;
    }
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    const unitPrice = BASE_PREMIUM[type] ?? 0;
    const componentPremium = count === BLOCK_SIZE ? BLOCK_PREMIUM : count * unitPrice;
    itemPremiums += componentPremium;
    policyBase += count * unitPrice;
  }

  return { itemPremiums, policyBase };
}

export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => {
    const { itemPremiums, policyBase } = computePremiumBreakdown(step.items);
    const firstInsuranceSurcharge = policyBase * 0.1;
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
    const premium = Math.ceil(itemPremiums + firstInsuranceSurcharge - loyaltyDiscount) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

