    Math.ceil(
      itemPremiums +
        firstInsuranceSurcharge -
        loyaltyDiscount -
        followUpDiscount,
    ) + PROCESSING_FEE;
  return { premium };
}

export function processScenario(scenario: any): unknown {
  const policies: Record<number, any[]> = {};
